class Solution(object):
    def numberOfPairs(self, points):
        n = len(points)
        count = 0
        for i in range(n):
            for j in range(n):
                ax, ay = points[i]
                bx, by = points[j]
                # A upper-left of B: ax <= bx and ay >= by
                if ax > bx or ay < by:
                    continue
                if ax == bx and ay == by:
                    continue
                # Check no other point inside rectangle [ax,bx] x [by,ay]
                valid = True
                for k in range(n):
                    if k == i or k == j:
                        continue
                    px, py = points[k]
                    if ax <= px <= bx and by <= py <= ay:
                        valid = False
                        break
                if valid:
                    count += 1
        return count
